import json
from typing import Union


def flatten_ec2_metadata(
    data: Union[dict, str],
    max_depth: int = 20
) -> dict:
    """
    Convert AWS EC2 instance metadata JSON response into a flattened dictionary with dot-notation keys.

    Parameters:
        data (Union[dict, str]): The EC2 metadata as a pre-parsed dict or a raw JSON string.
        max_depth (int): Maximum recursion depth allowed. Defaults to 20. A ValueError is raised
            when depth >= max_depth, so recursion never exceeds exactly max_depth levels.
            depth=0 represents the first level of keys, depth=1 the second, and so on.
            A ValueError is raised when depth reaches max_depth (i.e., at the 21st level when max_depth=20).

    Returns:
        dict: A flat dictionary where nested keys are joined with dot-notation
            (e.g., 'network.interfaces.0.mac'). If the root value is not a dict,
            returns {"" : <scalar_value>}.

    Raises:
        ValueError: If input is None or not a dict or str type.
        ValueError: If a JSON string input cannot be parsed by json.loads().
        ValueError: If recursion depth reaches max_depth.

    Examples:
        >>> flatten_ec2_metadata({"instanceId": "i-1234", "network": {"ip": "10.0.0.1"}})
        {'instanceId': 'i-1234', 'network.ip': '10.0.0.1'}

        >>> flatten_ec2_metadata('{"a": {"b": {"c": 1}}}', max_depth=2)
        Traceback (most recent call last):
            ...
        ValueError: Maximum recursion depth of 2 reached.
    """
    if data is None or not isinstance(data, (dict, str)):
        raise ValueError(
            f"Input must be a dict or str, got {type(data).__name__}."
        )

    if isinstance(data, str):
        try:
            data = json.loads(data)
        except json.JSONDecodeError as e:
            raise ValueError(f"Invalid JSON string: {e}")

    if not isinstance(data, dict):
        return {"": data}

    def _flatten(obj: dict, prefix: str, depth: int) -> dict:
        if depth >= max_depth:
            raise ValueError(f"Maximum recursion depth of {max_depth} reached.")
        result = {}
        for key, value in obj.items():
            new_key = prefix + "." + key if prefix else key
            if isinstance(value, dict):
                result.update(_flatten(value, new_key, depth + 1))
            elif isinstance(value, list):
                for i, item in enumerate(value):
                    indexed_key = new_key + "." + str(i)
                    if isinstance(item, dict):
                        result.update(_flatten(item, indexed_key, depth + 1))
                    else:
                        result[indexed_key] = item
            else:
                result[new_key] = value
        return result

    return _flatten(data, "", 0)

