  "$schema": "http://json-schema.org/draft-07/schema#",
  "title": "AWS Lambda Function Configuration",
  "description": "JSON schema for validating the structure of an AWS Lambda function configuration object, enforcing AWS-specific constraints and required fields.",
  "type": "object",
  "required": ["FunctionName", "Runtime", "Handler", "Role"],
  "additionalProperties": false,
  "properties": {
    "FunctionName": {
      "type": "string",
      "description": "The name of the Lambda function. Supports plain names (up to 64 chars) and full ARN format (up to 140 chars). Must match pattern ^[a-zA-Z0-9-_:]+$.",
      "pattern": "^[a-zA-Z0-9-_:]+$",
      "maxLength": 140
    },
    "Runtime": {
      "type": "string",
      "description": "The runtime environment for the Lambda function. Includes both current and legacy/deprecated AWS Lambda runtimes.",
      "enum": [
        "nodejs18.x",
        "nodejs16.x",
        "nodejs14.x",
        "nodejs12.x",
        "python3.11",
        "python3.10",
        "python3.9",
        "python3.8",
        "python3.7",
        "python3.6",
        "java17",
        "java11",
        "java8",
        "java8.al2",
        "dotnet7",
        "dotnet6",
        "dotnetcore3.1",
        "dotnetcore2.1",
        "go1.x",
        "ruby2.7",
        "ruby2.5",
        "provided",
        "provided.al2"
      ]
    },
    "Handler": {
      "type": "string",
      "description": "The function entrypoint in the form file.method. Must not contain whitespace and must be at most 128 characters, reflecting AWS Lambda limits.",
      "pattern": "^[^\\s]+$",
      "maxLength": 128
    },
    "Role": {
      "type": "string",
      "description": "The ARN of the IAM role that Lambda assumes when executing the function. Must match the AWS IAM role ARN format.",
      "pattern": "^arn:aws:iam::[0-9]{12}:role/.+$"
    },
    "Description": {
      "type": "string",
      "description": "A description of the Lambda function. Optional free-text field.",
      "maxLength": 256
    },
    "Timeout": {
      "type": "integer",
      "description": "The maximum time in seconds that the Lambda function can run before being terminated. Minimum is 1, maximum is 900 (15 minutes).",
      "minimum": 1,
      "maximum": 900
    },
    "MemorySize": {
      "type": "integer",
      "description": "The amount of memory in MB allocated to the Lambda function. Minimum is 128 MB, maximum is 10240 MB (10 GB).",
      "minimum": 128,
      "maximum": 10240
    },
    "Environment": {
      "type": "object",
      "description": "Environment configuration for the Lambda function, containing key-value pairs passed as environment variables at runtime.",
      "properties": {
        "Variables": {
          "type": "object",
          "description": "A map of environment variable key-value pairs. Keys must start with a letter and contain only letters, digits, and underscores. Maximum of 128 key-value pairs allowed per AWS limits.",
          "propertyNames": {
            "pattern": "^[a-zA-Z][a-zA-Z0-9_]*$",
            "description": "Environment variable key. Must start with a letter and contain only alphanumeric characters and underscores."
          },
          "additionalProperties": {
            "type": "string",
            "description": "The value of the environment variable. Must be a string."
          },
          "maxProperties": 128
        }
      },
      "additionalProperties": false
    },
    "VpcConfig": {
      "type": "object",
      "description": "VPC configuration for the Lambda function, enabling it to access resources within a VPC. Requires at least one subnet and one security group.",
      "required": ["SubnetIds", "SecurityGroupIds"],
      "additionalProperties": false,
      "properties": {
        "SubnetIds": {
          "type": "array",
          "description": "A list of VPC subnet IDs for the Lambda function. At least one subnet ID is required.",
          "items": {
            "type": "string",
            "description": "A VPC subnet ID."
          },
          "minItems": 1
        },
        "SecurityGroupIds": {
          "type": "array",
          "description": "A list of VPC security group IDs for the Lambda function. At least one security group ID is required.",
          "items": {
            "type": "string",
            "description": "A VPC security group ID."
          },
          "minItems": 1
        }
      }
    },
    "EphemeralStorage": {
      "type": "object",
      "description": "The ephemeral storage configuration for the Lambda function, specifying the size of /tmp directory in MB.",
      "required": ["Size"],
      "additionalProperties": false,
      "properties": {
        "Size": {
          "type": "integer",
          "description": "The size of the Lambda function's /tmp directory in MB. Minimum is 512 MB, maximum is 10240 MB (10 GB).",
          "minimum": 512,
          "maximum": 10240
        }
      }
    },
    "Tags": {
      "type": "object",
      "description": "A map of tags assigned to the Lambda function for resource organization and cost allocation.",
      "additionalProperties": {
        "type": "string",
        "description": "Tag value string."
      }
    }
  }
}
